import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const x=JSON.parse('{"title":"黄煌（经方派）","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/05-近现代/10-黄煌（经方派）.md","filePath":"tcm-data/05-近现代/10-黄煌（经方派）.md","lastUpdated":1781084559000}'),n={name:"tcm-data/05-近现代/10-黄煌（经方派）.md"};function d(o,t,s,g,i,f){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="黄煌-经方派" tabindex="-1">黄煌（经方派） <a class="header-anchor" href="#黄煌-经方派" aria-label="Permalink to &quot;黄煌（经方派）&quot;">​</a></h1><blockquote><p>黄煌（1954年生），江苏江阴人 当代经方派的代表人物，&quot;方证对应&quot;的推动者 代表作：《中医十大类方》《经方方证》《张仲景50味药证》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>籍贯</strong>：江苏江阴</li><li><strong>现任</strong>：南京中医药大学教授</li><li><strong>经历</strong>：早年研究中医体质学，后转攻《伤寒论》方证</li><li><strong>学术地位</strong>：<strong>当代经方派的旗手</strong>，&quot;方-证-人&quot;体系的创立者</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-方证对应-——-经方的精准使用" tabindex="-1">1. 方证对应 —— 经方的精准使用 <a class="header-anchor" href="#_1-方证对应-——-经方的精准使用" aria-label="Permalink to &quot;1. 方证对应 —— 经方的精准使用&quot;">​</a></h3><blockquote><p><strong>「方证是经方的灵魂。」</strong></p></blockquote><p>黄煌认为：《伤寒论》的核心不是理论，而是**&quot;方证&quot;**——什么证用什么方，简洁直接。</p><h3 id="_2-药证体质-——-方人-学说" tabindex="-1">2. 药证体质 —— &quot;方人&quot;学说 <a class="header-anchor" href="#_2-药证体质-——-方人-学说" aria-label="Permalink to &quot;2. 药证体质 —— &quot;方人&quot;学说&quot;">​</a></h3><p>黄煌的最大特色是：<strong>根据人的体质（体型、面色、心理、舌头）来选方</strong>。</p><table tabindex="0"><thead><tr><th style="text-align:left;">体质类型</th><th style="text-align:left;">特征</th><th style="text-align:left;">常用方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>桂枝体质</strong></td><td style="text-align:left;">白瘦、易出汗、易心悸</td><td style="text-align:left;">桂枝汤类</td></tr><tr><td style="text-align:left;"><strong>麻黄体质</strong></td><td style="text-align:left;">黑胖、无汗、易喘</td><td style="text-align:left;">麻黄汤类</td></tr><tr><td style="text-align:left;"><strong>柴胡体质</strong></td><td style="text-align:left;">中等体型、易紧张、胸胁满</td><td style="text-align:left;">柴胡汤类</td></tr><tr><td style="text-align:left;"><strong>大黄体质</strong></td><td style="text-align:left;">强壮、便秘、易出血</td><td style="text-align:left;">泻心汤类</td></tr><tr><td style="text-align:left;"><strong>黄芪体质</strong></td><td style="text-align:left;">虚胖、易汗、易浮肿</td><td style="text-align:left;">黄芪剂</td></tr><tr><td style="text-align:left;"><strong>半夏体质</strong></td><td style="text-align:left;">敏感、多疑、易恶心</td><td style="text-align:left;">半夏剂</td></tr></tbody></table><h3 id="_3-经方十类方" tabindex="-1">3. 经方十类方 <a class="header-anchor" href="#_3-经方十类方" aria-label="Permalink to &quot;3. 经方十类方&quot;">​</a></h3><p>黄煌将经方按功能分为十大类：</p><table tabindex="0"><thead><tr><th style="text-align:left;">类别</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>桂枝类</strong></td><td style="text-align:left;">桂枝汤、小建中汤</td></tr><tr><td style="text-align:left;"><strong>麻黄类</strong></td><td style="text-align:left;">麻黄汤、麻杏石甘汤</td></tr><tr><td style="text-align:left;"><strong>柴胡类</strong></td><td style="text-align:left;">小柴胡汤、四逆散</td></tr><tr><td style="text-align:left;"><strong>大黄类</strong></td><td style="text-align:left;">大承气汤、桃核承气汤</td></tr><tr><td style="text-align:left;"><strong>黄芪类</strong></td><td style="text-align:left;">黄芪建中汤、补中益气汤</td></tr><tr><td style="text-align:left;"><strong>石膏类</strong></td><td style="text-align:left;">白虎汤</td></tr><tr><td style="text-align:left;"><strong>黄连类</strong></td><td style="text-align:left;">黄连解毒汤、黄连阿胶汤</td></tr><tr><td style="text-align:left;"><strong>干姜类</strong></td><td style="text-align:left;">理中汤、四逆汤</td></tr><tr><td style="text-align:left;"><strong>附子类</strong></td><td style="text-align:left;">四逆汤、真武汤</td></tr><tr><td style="text-align:left;"><strong>半夏类</strong></td><td style="text-align:left;">小半夏汤、温胆汤</td></tr></tbody></table><h3 id="_4-腹诊" tabindex="-1">4. 腹诊 <a class="header-anchor" href="#_4-腹诊" aria-label="Permalink to &quot;4. 腹诊&quot;">​</a></h3><p>黄煌特别强调《伤寒论》中的<strong>腹诊</strong>，认为腹诊是经方使用的重要指征。</p><hr><h2 id="三、代表方剂-黄煌使用经验" tabindex="-1">三、代表方剂（黄煌使用经验） <a class="header-anchor" href="#三、代表方剂-黄煌使用经验" aria-label="Permalink to &quot;三、代表方剂（黄煌使用经验）&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">方证要点（黄煌特色）</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>小柴胡汤</strong></td><td style="text-align:left;">胸胁苦满、往来寒热、口苦咽干</td></tr><tr><td style="text-align:left;"><strong>四逆散</strong></td><td style="text-align:left;">紧张、压力大、四肢冷、脉弦</td></tr><tr><td style="text-align:left;"><strong>温胆汤</strong></td><td style="text-align:left;">焦虑、失眠、恶心、胆小</td></tr><tr><td style="text-align:left;"><strong>桂枝茯苓丸</strong></td><td style="text-align:left;">下腹部充实、皮肤粗糙、面红</td></tr><tr><td style="text-align:left;"><strong>大柴胡汤</strong></td><td style="text-align:left;">体格壮实、上腹饱满、便秘</td></tr><tr><td style="text-align:left;"><strong>真武汤</strong></td><td style="text-align:left;">精神萎靡、浮肿、脉沉、怕冷</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「方证是经方的灵魂。」</strong></p></blockquote><blockquote><p><strong>「中医的治病，不是理论治病，是方证治病。」</strong></p></blockquote><blockquote><p><strong>「学《伤寒论》，不是学理论，是学方证。」</strong></p></blockquote><blockquote><p><strong>「经方不传之秘，在于剂量。」</strong></p></blockquote><blockquote><p><strong>「一个方，就是一个人。理解了这个人，就理解了这张方。」</strong></p></blockquote><blockquote><p><strong>「经方不是老古董，是现代医学的补充。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li>&quot;方证体质&quot;学说使经方更容易被初学者掌握</li><li>推动了经方在日本、欧美的传播</li><li>&quot;方-证-人&quot;体系被广泛采用</li></ul><h3 id="黄煌-vs-黄元御" tabindex="-1">黄煌 vs 黄元御 <a class="header-anchor" href="#黄煌-vs-黄元御" aria-label="Permalink to &quot;黄煌 vs 黄元御&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">黄煌</th><th style="text-align:left;">黄元御</th></tr></thead><tbody><tr><td style="text-align:left;">方法</td><td style="text-align:left;">方证对应（经验主义）</td><td style="text-align:left;">理论指导（&quot;一气周流&quot;）</td></tr><tr><td style="text-align:left;">用药</td><td style="text-align:left;">经方原方为主</td><td style="text-align:left;">经方加减化裁</td></tr><tr><td style="text-align:left;">学习路径</td><td style="text-align:left;">从方入手</td><td style="text-align:left;">从理论入手</td></tr><tr><td style="text-align:left;">互补</td><td style="text-align:left;">临床实用</td><td style="text-align:left;">理论深刻</td></tr></tbody></table><hr><p><em>本条目为精简框架版。可扩展至十大类方详解、经方体质辨证体系等专题。</em></p>',36)])])}const y=e(n,[["render",d]]);export{x as __pageData,y as default};
